use std::collections::HashMap;
use std::sync::Arc;
use tokio::sync::Mutex;
use warp::{Filter, Rejection, Reply};

type WebHandler = Box<dyn Fn() -> String + Send + Sync>;

struct WebServer {
    routes: Arc<Mutex<HashMap<String, WebHandler>>>,
}

impl WebServer {
    fn new() -> Self {
        WebServer {
            routes: Arc::new(Mutex::new(HashMap::new())),
        }
    }

    async fn add_route(&self, path: String, handler: WebHandler) {
        let mut routes = self.routes.lock().await;
        routes.insert(path, handler);
    }

    async fn get_handler(&self, path: &str) -> Option<String> {
        let routes = self.routes.lock().await;
        routes.get(path).map(|handler| handler())
    }
}

#[tokio::main]
async fn main() {
    let server = WebServer::new();

    // Add routes with closures
    server.add_route("/home".to_string(), Box::new(|| {
        "<html><body><h1>Home Page</h1></body></html>".to_string()
    })).await;

    server.add_route("/about".to_string(), Box::new(|| {
        "<html><body><h1>About Page</h1></body></html>".to_string()
    })).await;

    // Create warp filter to handle requests
    let routes = warp::any()
        .and(warp::path::full())
        .and_then(move |path: warp::path::FullPath| {
            let server = server.clone();
            async move {
                match server.get_handler(path.as_str()).await {
                    Some(content) => Ok(warp::reply::html(content)),
                    None => Err(warp::reject::not_found()),
                }
            }
        });

    warp::serve(routes).run(([127, 0, 0, 1], 3030)).await;
}
