use std::sync::{Arc, Mutex};

type Middleware = Box<dyn Fn(&str, &str, &mut Vec<(String, String)>) + Send + Sync>;

struct Server {
    middlewares: Vec<Middleware>,
}

impl Server {
    fn new() -> Self {
        Server {
            middlewares: Vec::new(),
        }
    }

    fn add_middleware<F>(&mut self, middleware: F)
    where
        F: Fn(&str, &str, &mut Vec<(String, String)>) + 'static + Send + Sync,
    {
        self.middlewares.push(Box::new(middleware));
    }

    fn handle_connection(&self, mut stream: TcpStream) {
        let mut buffer = [0; 1024];
        stream.read(&mut buffer).unwrap();

        let request = String::from_utf8_lossy(&buffer[..]);
        let request_line = request.lines().next().unwrap_or("");
        let parts: Vec<&str> = request_line.split_whitespace().collect();
        if parts.len() < 2 {
            return;
        }
        let method = parts[0];
        let uri = parts[1];

        let mut headers = Vec::new();

        for middleware in &self.middlewares {
            middleware(method, uri, &mut headers);
        }

        let response = format!(
            "HTTP/1.1 200 OK\r\n{}\r\n\r\n{}",
            headers.iter()
                .map(|(k, v)| format!("{}: {}", k, v))
                .collect::<Vec<_>>()
                .join("\r\n"),
            "Request processed"
        );

        stream.write(response.as_bytes()).unwrap();
        stream.flush().unwrap();
    }

    fn run(&self, address: &str) {
        let listener = TcpListener::bind(address).unwrap();
        println!("Server running on {}", address);

        for stream in listener.incoming() {
            let stream = stream.unwrap();
            self.handle_connection(stream);
        }
    }
}

fn main() {
    let mut server = Server::new();

    // Middleware 1: Log request method and URI
    server.add_middleware(|method, uri, _| {
        println!("[INFO] {} {}", method, uri);
    });

    // Middleware 2: Append custom header
    server.add_middleware(|_, _, headers| {
        headers.push(("X-Processed-By".to_string(), "Rust-Server".to_string()));
    });

    server.run("127.0.0.1:8080");
}
