package main

import (
	"crypto/aes"
	"crypto/cipher"
	"crypto/rand"
	"io"
	"log"
	"os"
	"path/filepath"
	"sync"
)

type EncryptionResult struct {
	FilePath string
	Success  bool
	Error    error
}

func encryptFile(filePath string, key []byte, results chan<- EncryptionResult, wg *sync.WaitGroup) {
	defer wg.Done()

	fileData, err := os.ReadFile(filePath)
	if err != nil {
		results <- EncryptionResult{filePath, false, err}
		return
	}

	block, err := aes.NewCipher(key)
	if err != nil {
		results <- EncryptionResult{filePath, false, err}
		return
	}

	gcm, err := cipher.NewGCM(block)
	if err != nil {
		results <- EncryptionResult{filePath, false, err}
		return
	}

	nonce := make([]byte, gcm.NonceSize())
	if _, err = io.ReadFull(rand.Reader, nonce); err != nil {
		results <- EncryptionResult{filePath, false, err}
		return
	}

	encryptedData := gcm.Seal(nonce, nonce, fileData, nil)

	err = os.WriteFile(filePath+".enc", encryptedData, 0644)
	if err != nil {
		results <- EncryptionResult{filePath, false, err}
		return
	}

	results <- EncryptionResult{filePath, true, nil}
}

func main() {
	dir := "./files" // Specify your directory here
	key := make([]byte, 32) // 32 bytes for AES-256
	if _, err := rand.Read(key); err != nil {
		log.Fatal("Error generating key:", err)
	}

	files, err := os.ReadDir(dir)
	if err != nil {
		log.Fatal("Error reading directory:", err)
	}

	results := make(chan EncryptionResult, len(files))
	var wg sync.WaitGroup

	for _, file := range files {
		if file.IsDir() {
			continue
		}
		wg.Add(1)
		go encryptFile(filepath.Join(dir, file.Name()), key, results, &wg)
	}

	go func() {
		wg.Wait()
		close(results)
	}()

	for result := range results {
		if result.Success {
			log.Printf("Successfully encrypted: %s\n", result.FilePath)
		} else {
			log.Printf("Failed to encrypt %s: %v\n", result.FilePath, result.Error)
		}
	}
}
