import java.util.PriorityQueue

data class Task(val priority: Int, val execution: () -> Unit)

class TaskScheduler {
    private val taskQueue = PriorityQueue<Task>(compareByDescending { it.priority })

    fun addTask(priority: Int, execution: () -> Unit) {
        taskQueue.add(Task(priority, execution))
    }

    fun executeTasks() {
        while (taskQueue.isNotEmpty()) {
            val task = taskQueue.poll()
            task.execution()
        }
    }
}

fun main() {
    val scheduler = TaskScheduler()

    // Example usage
    scheduler.addTask(1) { println("Executing low priority task") }
    scheduler.addTask(3) { println("Executing high priority task") }
    scheduler.addTask(2) { println("Executing medium priority task") }

    scheduler.executeTasks()
}
