package main

import (
	"encoding/json"
	"fmt"
	"net"
	"sync"
)

type User struct {
	ID    int    `json:"id"`
	Name  string `json:"name"`
	Email string `json:"email"`
}

type Request struct {
	UserID int `json:"user_id"`
}

type Response struct {
	Status  string `json:"status"`
	Message string `json:"message"`
	User    *User  `json:"user,omitempty"`
}

func fetchUserFromDB(userID int, userChan chan<- *User, wg *sync.WaitGroup) {
	defer wg.Done()

	// Simulate database fetch
	user := &User{
		ID:    userID,
		Name:  fmt.Sprintf("User%d", userID),
		Email: fmt.Sprintf("user%d@example.com", userID),
	}
	userChan <- user
}

func processUser(userChan <-chan *User, resultChan chan<- *Response, wg *sync.WaitGroup) {
	defer wg.Done()

	user := <-userChan

	// Simulate processing
	if user.ID%2 == 0 {
		resultChan <- &Response{
			Status:  "success",
			Message: "User processed successfully",
			User:    user,
		}
	} else {
		resultChan <- &Response{
			Status:  "error",
			Message: "Failed to process user",
			User:    nil,
		}
	}
}

func handleConnection(conn net.Conn) {
	defer conn.Close()

	var req Request
	decoder := json.NewDecoder(conn)
	err := decoder.Decode(&req)
	if err != nil {
		resp := Response{
			Status:  "error",
			Message: "Invalid request format",
		}
		json.NewEncoder(conn).Encode(resp)
		return
	}

	userChan := make(chan *User, 1)
	resultChan := make(chan *Response, 1)

	var wg sync.WaitGroup
	wg.Add(2)

	go fetchUserFromDB(req.UserID, userChan, &wg)
	go processUser(userChan, resultChan, &wg)

	wg.Wait()

	resp := <-resultChan
	json.NewEncoder(conn).Encode(resp)
}

func main() {
	listener, err := net.Listen("tcp", ":8080")
	if err != nil {
		fmt.Println("Error starting server:", err)
		return
	}
	defer listener.Close()

	fmt.Println("Server started on :8080")

	for {
		conn, err := listener.Accept()
		if err != nil {
			fmt.Println("Error accepting connection:", err)
			continue
		}
		go handleConnection(conn)
	}
}
