fn celsius_to_fahrenheit(temps: Vec<f64>) -> Vec<f64> {
    temps.into_iter().map(|temp| {
        match temp {
            t if t < 0.0 => {
                // Freezing range: below 0°C
                t * 9.0 / 5.0 + 32.0
            },
            t if t >= 0.0 && t <= 15.0 => {
                // Cold range: 0°C to 15°C
                t * 9.0 / 5.0 + 32.0
            },
            t if t >= 16.0 && t <= 30.0 => {
                // Warm range: 16°C to 30°C
                t * 9.0 / 5.0 + 32.0
            },
            t if t > 30.0 => {
                // Hot range: above 30°C
                t * 9.0 / 5.0 + 32.0
            },
            _ => temp, // Fallback (unreachable for valid inputs)
        }
    }).collect()
}
