import io.ktor.server.engine.*
import io.ktor.server.netty.*
import com.auth0.jwt.JWT
import com.auth0.jwt.algorithms.Algorithm

fun main() {
    embeddedServer(Netty, port = 8080) {
        install(Authentication) {
            jwt("auth-jwt") {
                verifier(
                    JWT.require(Algorithm.HMAC256("secret"))
                        .withIssuer("your-issuer")
                        .build()
                )
                validate { credential ->
                    if (credential.payload.getClaim("username").asString() != "") {
                        JWTPrincipal(credential.payload)
                    } else {
                        null
                    }
                }
            }
        }

        routing {
            authenticate("auth-jwt") {
                post("/auth") {
                    val principal = call.principal<JWTPrincipal>()
                    val username = principal?.payload?.getClaim("username")?.asString()
                    val roles = principal?.payload?.getClaim("roles")?.asList(String::class.java) ?: emptyList()

                    val hasPermission: (String) -> Boolean = { requiredRole ->
                        roles.contains(requiredRole)
                    }

                    if (hasPermission("admin")) {
                        call.respond("Authenticated as admin")
                    } else {
                        call.respond("Authenticated but insufficient permissions")
                    }
                }
            }
        }
    }.start(wait = true)
}
